import './App.css';
import Navbar from './components/navbar';
import Footer from './components/footer';
import Abogadas from './components/abogadas';
import yuli from './assets/yuli.jpg';



function App() {
  return (
    <div className="App">
    <header className="header">
      <Navbar />
    </header>


      <div className="main">
        <h1>Bienvenidos a YGU Abogada y notariada publica</h1>
        <p>En YGU Abogada y notariada publica, nos dedicamos a brindar servicios legales de alta calidad con un enfoque personalizado. Nuestro equipo de abogadas altamente capacitadas se especializa en diversas áreas del derecho, incluyendo derecho civil, derecho penal, derecho laboral y derecho de familia. Nos comprometemos a ofrecer asesoramiento legal sólido y representación efectiva para proteger los derechos e intereses de nuestros clientes. En YGU, valoramos la confianza y la satisfacción de nuestros clientes, y trabajamos arduamente para lograr resultados exitosos en cada caso que manejamos.</p>
      </div>

      <div className="abogadas-container">
        <Abogadas 
          nombre="Yuliana Gonzalez Uribe"
          imagen={yuli}
          especialidades={["Derecho Civil", "Derecho Penal"]}
        />
        <Abogadas 
          nombre="Daniela Gonzalez Uribe"
          imagen={yuli}
          especialidades={["Derecho Civil", "Derecho Penal"]}
        />

      </div>
      <footer>
        <Footer />
      </footer>

    </div>
  );
}

export default App;
